    .{ .cp = 0x1E939, .members = .{ 0x1E917, 0x1E939, 0x0, 0x0 }, .len = 2 },
    .{ .cp = 0x1E93A, .members = .{ 0x1E918, 0x1E93A, 0x0, 0x0 }, .len = 2 },
    .{ .cp = 0x1E93B, .members = .{ 0x1E919, 0x1E93B, 0x0, 0x0 }, .len = 2 },
    .{ .cp = 0x1E93C, .members = .{ 0x1E91A, 0x1E93C, 0x0, 0x0 }, .len = 2 },
    .{ .cp = 0x1E93D, .members = .{ 0x1E91B, 0x1E93D, 0x0, 0x0 }, .len = 2 },
    .{ .cp = 0x1E93E, .members = .{ 0x1E91C, 0x1E93E, 0x0, 0x0 }, .len = 2 },
    .{ .cp = 0x1E93F, .members = .{ 0x1E91D, 0x1E93F, 0x0, 0x0 }, .len = 2 },
